#define THREADS 256

inline int mirror_coord(int d, int size)
{
    if (size <= 1) return 0;
    while (d >= size || d < 0) {
        if (d >= size) d = 2 * size - 2 - d;
        else d = -d;
    }
    return d;
}

inline int sample_mirrored(__global const int *in, int x, int y, int sx, int sy)
{
    x = mirror_coord(x, sx);
    y = mirror_coord(y, sy);
    return in[y * sx + x];
}

inline int vt53_at(__global const int *in, int x, int y, int sx, int sy)
{
    int c = sample_mirrored(in, x, y, sx, sy);

    if (y & 1) {
        int p = sample_mirrored(in, x, y - 1, sx, sy);
        int n = sample_mirrored(in, x, y + 1, sx, sy);
        return c - ((p + n) / 2);
    } else {
        int ym1 = sample_mirrored(in, x, y - 1, sx, sy);
        int ym2 = sample_mirrored(in, x, y - 2, sx, sy);
        int yp1 = sample_mirrored(in, x, y + 1, sx, sy);
        int yp2 = sample_mirrored(in, x, y + 2, sx, sy);

        int odd_prev = ym1 - ((ym2 + c) / 2);
        int odd_next = yp1 - ((c + yp2) / 2);

        return c + ((odd_prev + odd_next + 2) / 4);
    }
}

inline int dwt53_coeff(__global const int *in, int x, int y, int sx, int sy)
{
    int c = vt53_at(in, x, y, sx, sy);

    if (x & 1) {
        int p = vt53_at(in, x - 1, y, sx, sy);
        int n = vt53_at(in, x + 1, y, sx, sy);
        return c - ((p + n) / 2);
    } else {
        int xm1 = vt53_at(in, x - 1, y, sx, sy);
        int xm2 = vt53_at(in, x - 2, y, sx, sy);
        int xp1 = vt53_at(in, x + 1, y, sx, sy);
        int xp2 = vt53_at(in, x + 2, y, sx, sy);

        int odd_prev = xm1 - ((xm2 + c) / 2);
        int odd_next = xp1 - ((c + xp2) / 2);

        return c + ((odd_prev + odd_next + 2) / 4);
    }
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    int pixels)
{
    int gid = (int)get_global_id(0);
    if (gid < pixels) {
        int o = gid * 3;
        d_r[gid] = ((int)d_src[o + 0]) - 128;
        d_g[gid] = ((int)d_src[o + 1]) - 128;
        d_b[gid] = ((int)d_src[o + 2]) - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   int pixels)
{
    int gid = (int)get_global_id(0);
    int base = gid * 9;  // host launches alignedSize/9 work-items

    for (int k = 0; k < 9; k++) {
        int idx = base + k;
        if (idx < pixels) {
            d_c[idx] = ((int)d_src[idx]) - 128;
        }
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              int sizeX,
                              int sizeY,
                              int winSteps,
                              int WIN_SX,
                              int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    if (get_global_id(0) != 0 || get_global_id(1) != 0) return;

    int llW = (sizeX + 1) / 2;
    int llH = (sizeY + 1) / 2;
    int hlW = sizeX - llW;
    int hlH = llH;
    int lhW = llW;
    int lhH = sizeY - llH;
    int hhW = hlW;
    int hhH = lhH;

    int offLL = 0;
    int offHL = offLL + llW * llH;
    int offLH = offHL + hlW * hlH;
    int offHH = offLH + lhW * lhH;

    for (int y = 0; y < sizeY; y++) {
        for (int x = 0; x < sizeX; x++) {
            int coeff = dwt53_coeff(input, x, y, sizeX, sizeY);
            int outIdx;

            if ((y & 1) == 0) {
                if ((x & 1) == 0) {
                    outIdx = offLL + (y / 2) * llW + (x / 2);
                } else {
                    outIdx = offHL + (y / 2) * hlW + (x / 2);
                }
            } else {
                if ((x & 1) == 0) {
                    outIdx = offLH + (y / 2) * lhW + (x / 2);
                } else {
                    outIdx = offHH + (y / 2) * hhW + (x / 2);
                }
            }

            output[outIdx] = coeff;
        }
    }
}
